import type { ChapterId, StudyQuestion } from "../types/study";
import { edbQuestionSeeds } from "./edbQuestionBank";
import { linkedStructuresQuestionSeeds } from "./linkedStructuresQuestions";
import { sortingQuestionSeeds } from "./sortingQuestions";

export type QuestionSeed = Omit<StudyQuestion, "id" | "options" | "correctAnswer"> & {
  answer: string;
  distractors: string[];
};

const labels = ["A", "B", "C", "D", "E"] as const;

const inferKind = (seed: QuestionSeed): NonNullable<StudyQuestion["kind"]> => {
  if (seed.kind) return seed.kind;
  const text = `${seed.prompt} ${seed.theme}`.toLowerCase();
  if (text.includes("complexidade") || text.includes("big o")) return "complexidade";
  if (text.includes("erro de compilação") || text.includes("causa erro")) return "erro de compilação";
  if (text.includes("estado final") || text.includes("ordem final")) return "estado final";
  if (text.includes("qual será") || text.includes("qual saída") || text.includes("o que será impresso")) return "saída do programa";
  if (text.includes("corrige") || text.includes("implementar") || text.includes("sequência")) return "implementação";
  return seed.code ? "interpretação de código" : "conceito";
};

const makeQuestion = (seed: QuestionSeed, index: number, correctIndex: number): StudyQuestion => {
  const choices = [seed.answer, ...seed.distractors];
  const options = choices
    .map((text, position) => ({ text, position: (position + correctIndex) % labels.length }))
    .sort((a, b) => a.position - b.position)
    .map(({ text }, position) => ({ label: labels[position], text }));

  return {
    ...seed,
    id: `q-${seed.chapter}-${String(index + 1).padStart(3, "0")}`,
    options,
    correctAnswer: labels[correctIndex],
    kind: inferKind(seed),
  };
};

const seededShuffle = <T,>(items: T[], seed: number) => {
  const shuffled = [...items];
  let state = seed;
  const random = () => {
    state = (state * 1664525 + 1013904223) >>> 0;
    return state / 0x100000000;
  };
  for (let index = shuffled.length - 1; index > 0; index -= 1) {
    const target = Math.floor(random() * (index + 1));
    [shuffled[index], shuffled[target]] = [shuffled[target], shuffled[index]];
  }
  return shuffled;
};

